#[cfg(test)]
mod tests {
    use super::*;
    use mockall::{mock, predicate::eq};

    mock! {
        Database {}
        impl Database {
            async fn fetch_user_by_id(&self, id: i32) -> Result<Option<User>, sqlx::Error>;
            async fn fetch_user_by_email(&self, email: &str) -> Result<Option<User>, sqlx::Error>;
        }
    }

    #[tokio::test]
    async fn test_get_by_id_not_found() {
        let mut db = MockDatabase::new();
        db.expect_fetch_user_by_id().with(eq(999)).returning(|_| Ok(None));
        let svc = UserService::new(&db);
        assert!(matches!(svc.get_by_id(999).await, Err(AppError::NotFound(_))));
    }

    #[tokio::test]
    async fn test_create_rejects_duplicate_email() {
        let mut db = MockDatabase::new();
        db.expect_fetch_user_by_email().returning(|_| Ok(Some(test_user())));
        let svc = UserService::new(&db);
        assert!(matches!(
            svc.create("John", "john@example.com", "pass").await,
            Err(AppError::Conflict(_))
        ));
    }
}

use axum::{body::Body, http::{Request, StatusCode}};
use tower::ServiceExt;
use serde_json::json;

#[tokio::test]
async fn test_create_user_returns_201() {
    let app = build_test_app().await;
    let response = app
        .oneshot(
            Request::builder()
                .method("POST")
                .uri("/api/v1/users")
                .header("Content-Type", "application/json")
                .body(Body::from(json!({"name":"John","email":"j@e.com","password":"pass123"}).to_string()))
                .unwrap(),
        )
        .await
        .unwrap();
    assert_eq!(response.status(), StatusCode::CREATED);
}
